```c
#include <stdint.h>
#include <stdbool.h>

#define RING_SIZE 256  // Must be power of 2
#define RING_MASK (RING_SIZE - 1)

typedef struct {
    volatile uint8_t buffer[RING_SIZE];
    volatile uint32_t head;  // Written by producer (ISR)
    volatile uint32_t tail;  // Written by consumer (main)
} RingBuffer;

void ring_init(RingBuffer *rb) {
    rb->head = 0;
    rb->tail = 0;
}

// Called from ISR — adds a byte
bool ring_put(RingBuffer *rb, uint8_t byte) {
    uint32_t next = (rb->head + 1) & RING_MASK;
    if (next == rb->tail) return false;  // Full
    rb->buffer[rb->head] = byte;
    rb->head = next;
    return true;
}

// Called from main loop — gets a byte
bool ring_get(RingBuffer *rb, uint8_t *byte) {
    if (rb->head == rb->tail) return false;  // Empty
    *byte = rb->buffer[rb->tail];
    rb->tail = (rb->tail + 1) & RING_MASK;
    return true;
}

bool ring_empty(RingBuffer *rb) {
    return rb->head == rb->tail;
}
```

**Key design decisions:**
- Power-of-2 size enables `& MASK` instead of `% SIZE` (faster, no division)
- Single producer, single consumer — no lock needed (each side only writes its own index)
- `volatile` on head/tail because ISR and main loop access them
- Wastes one slot to distinguish full from empty (alternative: keep a count, but that requires atomic ops)

