#include <stdatomic.h>
#include <stdint.h>
#include <stdbool.h>
#include <string.h>

// Size MUST be a power of 2 for efficient index masking
#define SPSC_SIZE 256
#define SPSC_MASK (SPSC_SIZE - 1)

typedef struct {
    uint8_t     buf[SPSC_SIZE];
    atomic_uint head; // Written by consumer only
    atomic_uint tail; // Written by producer only
    uint8_t     _pad[64]; // Prevent false sharing between head and tail
} SPSC_Ring;

void spsc_init(SPSC_Ring *r) {
    atomic_init(&r->head, 0);
    atomic_init(&r->tail, 0);
}

// Producer (ISR): returns false if full
bool spsc_put(SPSC_Ring *r, uint8_t byte) {
    unsigned tail = atomic_load_explicit(&r->tail, memory_order_relaxed);
    unsigned next = (tail + 1) & SPSC_MASK;
    // Read head with acquire so we see consumer's updates
    if (next == atomic_load_explicit(&r->head, memory_order_acquire))
        return false; // Full
    r->buf[tail] = byte;
    // Release ensures buf write is visible before tail update
    atomic_store_explicit(&r->tail, next, memory_order_release);
    return true;
}

// Consumer (task): returns false if empty
bool spsc_get(SPSC_Ring *r, uint8_t *out) {
    unsigned head = atomic_load_explicit(&r->head, memory_order_relaxed);
    // Acquire on tail so we see producer's buf writes
    if (head == atomic_load_explicit(&r->tail, memory_order_acquire))
        return false; // Empty
    *out = r->buf[head];
    atomic_store_explicit(&r->head, (head + 1) & SPSC_MASK, memory_order_release);
    return true;
}

size_t spsc_available(SPSC_Ring *r) {
    unsigned tail = atomic_load_explicit(&r->tail, memory_order_acquire);
    unsigned head = atomic_load_explicit(&r->head, memory_order_acquire);
    return (tail - head) & SPSC_MASK;
}
```

**Why this works (memory ordering):**
- **Producer:** loads tail with `relaxed` (only it writes tail). Loads head with `acquire` to see consumer's latest read position. Writes buf then stores tail with `release` — guarantees buf is visible to consumer before tail update.
- **Consumer:** loads head with `relaxed` (only it writes head). Loads tail with `acquire` to see producer's latest write. Reads buf after acquire. Stores head with `release`.
- The acquire/release pair on tail (producer release → consumer acquire) creates a happens-before relationship: consumer sees buf data written before the tail update.

**Why no locks:** ISRs can't block. Any lock that sleeps is forbidden. Even spinlocks are dangerous in ISR context on single-core (you'd spin forever). SPSC is naturally safe for one producer and one consumer without locks because each side owns exactly one index.

**Firmware usage patterns:**
```c
// UART RX ISR (producer):
void UART_RX_ISR(void) {
    uint8_t byte = UART->DR;
    if (!spsc_put(&uart_rx_ring, byte))
        rx_overflow_count++; // Count drops, don't block!
}

// Main task (consumer):
while (spsc_get(&uart_rx_ring, &byte)) {
    process_byte(byte);
}
```

**On ARM without C11 atomics (embedded toolchains):**
```c
// Fallback: use __atomic builtins or volatile + DMB
__atomic_store_n(&r->tail, next, __ATOMIC_RELEASE);
__atomic_load_n(&r->head, __ATOMIC_ACQUIRE);
```

