#include <stdio.h>
#include <stdlib.h>

typedef struct { int start, end; } Interval;

int cmp_interval(const void *a, const void *b) {
    return ((Interval*)a)->start - ((Interval*)b)->start;
}

// Returns number of merged intervals in out[]
// out must have capacity >= count
int merge_intervals(Interval *in, int count, Interval *out) {
    if (count == 0) return 0;

    // Sort by start time
    qsort(in, count, sizeof(Interval), cmp_interval);

    int n = 0;
    out[n] = in[0];

    for (int i = 1; i < count; i++) {
        if (in[i].start <= out[n].end) {
            // Overlapping: extend current interval
            if (in[i].end > out[n].end)
                out[n].end = in[i].end;
        } else {
            // Gap: start new interval
            out[++n] = in[i];
        }
    }
    return n + 1;
}
```

**Algorithm:**
1. Sort by start (O(n log n))
2. Walk once: if current interval overlaps with the last merged, extend; otherwise push new
3. O(n) for the merge pass → O(n log n) overall

**Firmware use cases:**
- **Dirty region tracking:** LCD partial refresh — collect all dirty rects from a frame, merge overlapping regions, then do one DMA per merged region instead of per widget update
- **DMA scatter-gather:** Merge adjacent memory regions to reduce DMA descriptor count
- **Timer scheduling:** Merge overlapping wake windows to reduce power transitions
- **Flash wear leveling:** Merge adjacent write requests into single sector erase

