```cpp
#include <cstdint>

// Integer math helpers — all constexpr (no floating point)
constexpr uint32_t abs_diff(uint32_t a, uint32_t b) { return a > b ? a - b : b - a; }
constexpr uint32_t pct_err_x100(uint32_t actual, uint32_t target) {
    return (abs_diff(actual, target) * 10000u) / target;
}

struct UartConfig {
    uint32_t brr;          // BRR register value
    uint32_t actual_baud;  // Achieved baud rate
    uint32_t error_x100;   // Error in units of 0.01%
};

// STM32-style BRR: PCLK / (16 * baud), with fractional bits [3:0]
constexpr UartConfig calc_brr(uint32_t pclk, uint32_t baud) {
    uint32_t div_int  = pclk / (16u * baud);
    // Fractional part: round to nearest 1/16
    uint32_t div_frac = ((pclk % (16u * baud)) * 16u + (16u * baud / 2u))
                        / (16u * baud);
    uint32_t brr    = (div_int << 4u) | (div_frac & 0x0Fu);
    uint32_t actual = pclk / (((brr >> 4u) * 16u) + (brr & 0x0Fu));
    return { brr, actual, pct_err_x100(actual, baud) };
}

// Template struct: compile-time validated baud rate config
template<uint32_t PCLK_HZ, uint32_t BAUD>
struct UartBaud {
    static constexpr UartConfig cfg = calc_brr(PCLK_HZ, BAUD);

    // BUILD ERROR if baud rate error > 2.00%
    static_assert(cfg.error_x100 <= 200u,
        "UART baud rate error exceeds 2% — choose a different clock or baud rate");

    static constexpr uint32_t brr    = cfg.brr;
    static constexpr uint32_t actual = cfg.actual_baud;
    static constexpr uint32_t error  = cfg.error_x100;
};

// Usage — all resolved at COMPILE TIME:
constexpr uint32_t APB1_CLK = 84'000'000;  // STM32F4 @ 84 MHz

using Baud9600   = UartBaud<APB1_CLK, 9600>;
using Baud115200 = UartBaud<APB1_CLK, 115200>;
using Baud460800 = UartBaud<APB1_CLK, 460800>;

// This would cause a COMPILE ERROR (uncomment to test):
// using BadBaud = UartBaud<APB1_CLK, 1'234'567>; // Error > 2%

// Driver: the BRR value is a compile-time constant — single MOV instruction
template<typename BaudCfg>
void uart_init(USART_TypeDef* uart) {
    uart->BRR = BaudCfg::brr;  // Compiler emits: MOV r3, #<constant>
    uart->CR1 |= USART_CR1_UE | USART_CR1_TE | USART_CR1_RE;
}

// Example: uart_init<Baud115200>(USART1);
```

**Why this is powerful:**
1. **Zero runtime overhead** — `BaudCfg::brr` is a compile-time integer constant; the compiler emits a single `MOV` instruction
2. **Build-time validation** — misconfiguring a baud rate for the wrong clock is a compile error, not a field bug
3. **Self-documenting** — `UartBaud<84000000, 115200>` expresses exactly what's configured
4. **No magic numbers** — derived from first principles, traceable in code review

**static_assert as a design tool:**
```cpp
// All caught at BUILD TIME with a clear message:
static_assert(sizeof(PacketHeader) == 8,   "Protocol header size changed — check spec");
static_assert(MAX_TASKS <= 32,             "Task count exceeds bitmap width");
static_assert(FLASH_PAGE_SIZE % sizeof(Config) == 0, "Config doesn't fit in flash page");
```

